mapper.select:
SELECT c.card_product_id AS id, c.persona_id AS personaId, c.created_time AS createdTime
FROM card_product c
WHERE c.created_time > #{since}

SELECT d.deposit_product_id AS id, d.persona_id AS personaId, d.created_time AS createdTime
FROM deposit_product d
WHERE d.created_time > #{since}

SELECT s.saving_product_id AS id, s.persona_id AS personaId, s.created_time AS createdTime
FROM saving_product s
WHERE s.created_time > #{since}

SELECT u.user_id
FROM users u
WHERE u.persona_id = #{personaId}

SELECT COUNT(*) FROM push_sent_log
WHERE user_id = #{userId}
AND product_type = #{type}
AND product_id = #{productId}
LIMIT 1
